1	// Match finding logic for detecting tile matches and special formations
2	
3	import { getTileValue, isNormal, isCursed, isTilePlusTile } from "./tile-helpers.js";
4	import { canMatch } from "./board.js";
5	
6	export function hasMatches(game) {
7	    return findMatches(game).length > 0;
8	}
9	
10	// Check if a swap between two positions creates matches involving those positions
11	export function hasMatchesForSwap(game, row1, col1, row2, col2) {
12	    const matches = findMatches(game);
13	
14	    // Check if any match contains either of the swapped positions
15	    return matches.some((match) => {
16	        return match.tiles.some((tile) => {
17	            return (tile.row === row1 && tile.col === col1) || (tile.row === row2 && tile.col === col2);
18	        });
19	    });
20	}
21	
22	export function findMatches(game) {
23	    // Find all matches with priority: 5-line > T > L > 4-line > Block > 3-line
24	    const allMatches = [
25	        ...findLineMatches(game, 5),
26	        ...findSpecialFormations(game, "T"),
27	        ...findSpecialFormations(game, "L"),
28	        ...findLineMatches(game, 4),
29	        ...findSpecialFormations(game, "Block"),
30	        ...findLineMatches(game, 3),
31	    ];
32	
33	    // Remove overlapping matches (keep higher priority)
34	    return filterOverlappingMatches(allMatches);
35	}
36	
37	
38	
39	function findLineMatches(game, targetLength) {
40	    const matches = [];
41	
42	    // Scan horizontally
43	    for (let row = 0; row < game.boardHeight; row++) {
44	        matches.push(...scanLine(game, row, true, targetLength));
45	    }
46	
47	    // Scan vertically
48	    for (let col = 0; col < game.boardWidth; col++) {
49	        matches.push(...scanLine(game, col, false, targetLength));
50	    }
51	
52	    return matches;
53	}
54	
55	function scanLine(game, index, isHorizontal, targetLength) {
56	    const matches = [];
57	    const length = isHorizontal ? game.boardWidth : game.boardHeight;
58	
59	    let matchGroup = [];
60	    let referenceTile = null; // First tile in group - all tiles must match this
61	    let maxValue = null;
62	
63	    for (let i = 0; i < length; i++) {
64	        const [row, col] = isHorizontal ? [index, i] : [i, index];
65	        const tile = game.board[row][col];
66	        const value = getTileValue(tile);
67	
68	        // Check if tile can be part of current match (normal or cursed tiles)
69	        if ((isNormal(tile) || isCursed(tile)) && value !== 0) {
70	            if (matchGroup.length === 0) {
71	                // Start new match
72	                matchGroup.push({ row, col });
73	                referenceTile = tile;
74	                maxValue = value;
75	            } else {
76	                // Try to extend match - must match REFERENCE tile, not just previous
77	                // This prevents plus-tiles from bridging different values
78	                if (canMatch(tile, referenceTile, game)) {
79	                    matchGroup.push({ row, col });
80	                    if (value > maxValue) {
81	                        maxValue = value;
82	                    }
83	                } else {
84	                    // End current match and start new one
85	                    if (matchGroup.length >= targetLength) {
86	                        const matchTiles = matchGroup.slice(0, targetLength);
87	                        matches.push(createLineMatch(matchTiles, maxValue, isHorizontal));
88	                    }
89	                    matchGroup = [{ row, col }];
90	                    referenceTile = tile;
91	                    maxValue = value;
92	                }
93	            }
94	        } else {
95	            // End current match
96	            if (matchGroup.length >= targetLength) {
97	                const matchTiles = matchGroup.slice(0, targetLength);
98	                matches.push(createLineMatch(matchTiles, maxValue, isHorizontal));
99	            }
100	            matchGroup = [];
101	            referenceTile = null;
102	            maxValue = null;
103	        }
104	    }
105	
106	    // Check remaining match at end
107	    if (matchGroup.length >= targetLength) {
108	        const matchTiles = matchGroup.slice(0, targetLength);
109	        matches.push(createLineMatch(matchTiles, maxValue, isHorizontal));
110	    }
111	
112	    return matches;
113	}
114	
115	function createLineMatch(tiles, value, isHorizontal) {
116	    const direction = isHorizontal ? "horizontal" : "vertical";
117	    const formationType =
118	        tiles.length === 4 ? `line_4_${direction}` : tiles.length === 5 ? `line_5_${direction}` : direction;
119	
120	    return {
121	        tiles: [...tiles],
122	        value,
123	        direction: formationType,
124	    };
125	}
126	
127	function findSpecialFormations(game, type) {
128	    const formations = [];
129	
130	    for (let row = 0; row < game.boardHeight; row++) {
131	        for (let col = 0; col < game.boardWidth; col++) {
132	            const tile = game.board[row][col];
133	            if (!isNormal(tile) && !isCursed(tile)) continue;
134	
135	            const value = getTileValue(tile);
136	            if (value === 0) continue;
137	
138	            let formation = null;
139	            if (type === "T") {
140	                formation = checkTFormation(game, row, col, value);
141	            } else if (type === "L") {
142	                formation = checkLFormation(game, row, col, value);
143	            } else if (type === "Block") {
144	                formation = checkBlockFormation(game, row, col, value);
145	            }
146	
147	            if (formation) {
148	                // Calculate max value from all tiles in the formation (for Plus tile support)
149	                const maxValue = getMaxValueFromPositions(game, formation.tiles);
150	                formation.value = maxValue;
151	                formations.push(formation);
152	            }
153	        }
154	    }
155	
156	    return formations;
157	}
158	
159	// Get maximum value from a list of tile positions (for Plus tile matching)
160	function getMaxValueFromPositions(game, positions) {
161	    let maxValue = 0;
162	    for (const pos of positions) {
163	        const tile = game.board[pos.row]?.[pos.col];
164	        if (tile) {
165	            const value = getTileValue(tile);
166	            if (value > maxValue) {
167	                maxValue = value;
168	            }
169	        }
170	    }
171	    return maxValue;
172	}
173	
174	export function checkTFormation(game, row, col, value) {
175	    // T-formation: 3 tiles in one direction + 2 tiles perpendicular at center
176	    const patterns = [
177	        { horizontal: [-1, 0, 1], vertical: [1, 2] }, // T down
178	        { vertical: [-1, 0, 1], horizontal: [1, 2] }, // T right
179	        { horizontal: [-1, 0, 1], vertical: [-2, -1] }, // T up
180	        { vertical: [-1, 0, 1], horizontal: [-2, -1] }, // T left
181	    ];
182	
183	    for (const pattern of patterns) {
184	        const result = checkPattern(game, row, col, value, pattern);
185	        if (result && result.positions.length === 5) {
186	            // Find overlapping line matches and add their tiles (only during user swaps)
187	            let allTiles = result.positions;
188	            if (game.isUserSwap) {
189	                const additionalTiles = findOverlappingLineMatches(game, result.positions, value);
190	                allTiles = [...result.positions, ...additionalTiles];
191	            }
192	
193	            return {
194	                tiles: allTiles,
195	                value,
196	                direction: "T-formation",
197	                intersection: { row, col },
198	            };
199	        }
200	    }
201	
202	    return null;
203	}
204	
205	export function checkLFormation(game, row, col, value) {
206	    // L-formation: 3 tiles horizontal + 3 tiles vertical with shared corner
207	    const patterns = [
208	        { horizontal: [0, 1, 2], vertical: [0, 1, 2] }, // L right-down
209	        { horizontal: [0, -1, -2], vertical: [0, 1, 2] }, // L left-down
210	        { horizontal: [0, 1, 2], vertical: [0, -1, -2] }, // L right-up
211	        { horizontal: [0, -1, -2], vertical: [0, -1, -2] }, // L left-up
212	    ];
213	
214	    const cornerTile = game.board[row]?.[col];
215	
216	    for (const pattern of patterns) {
217	        // For L, vertical should skip first offset (corner already counted)
218	        const positions = [];
219	        let valid = true;
220	
221	        // Check horizontal
222	        for (const offset of pattern.horizontal) {
223	            const result = getTileAt(game, row, col + offset);
224	            if (!result || !canMatch(result.tile, cornerTile, game)) {
225	                valid = false;
226	                break;
227	            }
228	            positions.push(result.pos);
229	        }
230	
231	        if (!valid) continue;
232	
233	        // Check vertical (skip first - it's the corner)
234	        for (let i = 1; i < pattern.vertical.length; i++) {
235	            const result = getTileAt(game, row + pattern.vertical[i], col);
236	            if (!result || !canMatch(result.tile, cornerTile, game)) {
237	                valid = false;
238	                break;
239	            }
240	            positions.push(result.pos);
241	        }
