                board: node.board,
                levelGoals: node.goals,
            };
            const result = simulateMove(simGame, swap, {
                rng: childRng,
                levelGoals: node.goals,
                initialBlockedTileCount,
            });

            console.log(`[solver]   swap (${swap.row1},${swap.col1})->(${swap.row2},${swap.col2}): valid=${result.valid} allGoalsSatisfied=${result.allGoalsSatisfied} goals=${JSON.stringify(result.levelGoals)}`);

